        private static string GetCanonicalTableName(string tableName)
        {
            foreach (var allowed in AllowedTables)
            {
                if (string.Equals(allowed, tableName, StringComparison.OrdinalIgnoreCase))
                    return allowed;
            }
            throw new ArgumentException($"Invalid table name: {tableName}");
        }

        private static string GetCanonicalColumnName(string columnName, string tableName)
        {
            if (AllowedColumns.TryGetValue(tableName, out var columns))
            {
                foreach (var col in columns)
                {
                    if (string.Equals(col, columnName, StringComparison.OrdinalIgnoreCase))
                        return col;
                }
            }
            throw new ArgumentException($"Invalid column '{columnName}' for table '{tableName}'");
        }

        private static bool IsValidColumn(string columnName, string tableName)
        {
            return AllowedColumns.TryGetValue(tableName, out var columns)
                   && columns.Contains(columnName);
        }

        private static string ParseSelectColumns(string selectParam, string tableName)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
                return "*";

            var parts = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries);
            var validatedColumns = new List<string>();

            foreach (var part in parts)
            {
                var col = part.Trim();
                if (!IsValidColumn(col, tableName))
                    throw new ArgumentException($"Invalid column in select: {col}");

                validatedColumns.Add($"[{GetCanonicalColumnName(col, tableName)}]");
            }

            return validatedColumns.Count > 0 ? string.Join(", ", validatedColumns) : "*";
        }

        private static (string filterClause, List<SqlParameter> parameters) ParseFilters(
            IQueryCollection query, string tableName)
        {
            var conditions = new List<string>();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            foreach (var key in query.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                // Expected format: filter_ColumnName_operator
                var filterParts = key.Substring(7).Split('_');
                if (filterParts.Length < 2)
                    throw new ArgumentException($"Invalid filter format: {key}. Expected: filter_ColumnName_operator");

                // The operator is the last part; column name is everything before it
                string op = filterParts[filterParts.Length - 1];
                string columnName = string.Join("_", filterParts, 0, filterParts.Length - 1);

                if (!IsValidColumn(columnName, tableName))
                    throw new ArgumentException($"Invalid filter column: {columnName}");

                if (!AllowedOperators.Contains(op))
                    throw new ArgumentException($"Invalid filter operator: {op}. Allowed: {string.Join(", ", AllowedOperators)}");

                string safeColumn = GetCanonicalColumnName(columnName, tableName);
                string value = query[key];

                var (condition, condParams) = BuildCondition(safeColumn, op, value, ref paramIndex);
                conditions.Add(condition);
                parameters.AddRange(condParams);
            }

            string filterClause = conditions.Count > 0
                ? string.Join(" AND ", conditions)
                : "";

            return (filterClause, parameters);
        }

        private static (string filterClause, List<SqlParameter> parameters) BuildFiltersFromBody(
            List<FilterCondition> filters, string tableName)
        {
            var conditions = new List<string>();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            if (filters == null || filters.Count == 0)
                return ("", parameters);

            foreach (var filter in filters)
            {
                if (string.IsNullOrWhiteSpace(filter.Column))
                    throw new ArgumentException("Filter column is required.");

                if (!IsValidColumn(filter.Column, tableName))
                    throw new ArgumentException($"Invalid filter column: {filter.Column}");

                string op = filter.Operator ?? "eq";
                if (!AllowedOperators.Contains(op))
                    throw new ArgumentException($"Invalid filter operator: {op}");

                string safeColumn = GetCanonicalColumnName(filter.Column, tableName);

                var (condition, condParams) = BuildCondition(safeColumn, op, filter.Value, ref paramIndex);
                conditions.Add(condition);
                parameters.AddRange(condParams);
            }

            string filterClause = conditions.Count > 0
                ? string.Join(" AND ", conditions)
                : "";

            return (filterClause, parameters);
        }

        private static (string condition, List<SqlParameter> parameters) BuildCondition(
            string safeColumn, string op, string value, ref int paramIndex)
        {
            var parameters = new List<SqlParameter>();
            string condition;

            switch (op.ToLowerInvariant())
            {
                case "eq":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] = {paramName}";
                        parameters.Add(new SqlParameter(paramName, value ?? (object)DBNull.Value));
                        break;
                    }
                case "neq":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] <> {paramName}";
                        parameters.Add(new SqlParameter(paramName, value ?? (object)DBNull.Value));
                        break;
                    }
                case "gt":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] > {paramName}";
                        parameters.Add(new SqlParameter(paramName, value));
                        break;
                    }
                case "gte":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] >= {paramName}";
                        parameters.Add(new SqlParameter(paramName, value));
                        break;
                    }
                case "lt":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] < {paramName}";
                        parameters.Add(new SqlParameter(paramName, value));
                        break;
                    }
                case "lte":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] <= {paramName}";
                        parameters.Add(new SqlParameter(paramName, value));
                        break;
                    }
                case "like":
                    {
                        string paramName = $"@p{paramIndex++}";
                        condition = $"[{safeColumn}] LIKE {paramName}";
                        // Wrap with wildcards for convenience; user can also pass their own pattern
                        string likeValue = value != null && !value.Contains('%') && !value.Contains('_')
                            ? $"%{value}%"
                            : value;
                        parameters.Add(new SqlParameter(paramName, likeValue ?? (object)DBNull.Value));
                        break;
                    }
                case "in":
                    {
                        if (string.IsNullOrWhiteSpace(value))
                            throw new ArgumentException($"IN operator requires comma-separated values for column {safeColumn}");

                        var values = value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                        var inParams = new List<string>();
                        foreach (var v in values)
                        {
                            string paramName = $"@p{paramIndex++}";
                            inParams.Add(paramName);
                            parameters.Add(new SqlParameter(paramName, v.Trim()));
                        }
                        condition = $"[{safeColumn}] IN ({string.Join(", ", inParams)})";
                        break;
                    }
                default:
                    throw new ArgumentException($"Unsupported operator: {op}");
            }

            return (condition, parameters);
        }

        private static string ParseOrderBy(string orderByParam, string tableName)
        {
            if (string.IsNullOrWhiteSpace(orderByParam))
                return "";

            var parts = orderByParam.Split(',', StringSplitOptions.RemoveEmptyEntries);
            var orderParts = new List<string>();

            foreach (var part in parts)
            {
                var segments = part.Trim().Split('_');
                if (segments.Length == 0)
                    continue;

                // Last segment might be ASC/DESC
                string direction = "ASC";
                string columnName;

                if (segments.Length >= 2 && AllowedSortDirections.Contains(segments[segments.Length - 1]))
                {
                    direction = segments[segments.Length - 1].ToUpperInvariant();
                    columnName = string.Join("_", segments, 0, segments.Length - 1);
                }
                else
                {
                    columnName = string.Join("_", segments);
                }

                if (!IsValidColumn(columnName, tableName))
                    throw new ArgumentException($"Invalid sort column: {columnName}");

                orderParts.Add($"[{GetCanonicalColumnName(columnName, tableName)}] {direction}");
            }

            return string.Join(", ", orderParts);
        }

        private static int ParseInt(string value, int defaultValue, int min, int max)
        {
            if (string.IsNullOrWhiteSpace(value))
                return defaultValue;

            if (int.TryParse(value, out int result))
                return Math.Clamp(result, min, max);

            return defaultValue;
        }
